// Data/Entities/IEntity.cs
public interface IEntity
{
    public Guid Id { get; set; }
}

// Data/Entities/Entity.cs
public class Entity : IEntity
{
    public Guid Id { get; set; }
}

// Data/Entities/TrackedEntity.cs
public class TrackedEntity : Entity
{
    public DateTime CreatedDate { get; set; }
    public Guid CreatedById { get; set; }
    public DateTime? UpdatedDate { get; set; }
    public Guid? UpdatedById { get; set; }
}

// Data/Entities/ITenantEntity.cs
public interface ITenantEntity
{
    Guid TenantId { get; set; }
}

// Data/Entities/ISoftDeletable.cs
public interface ISoftDeletable
{
    bool IsDeleted { get; set; }
    DateTime? DeletedDate { get; set; }
    Guid? DeletedById { get; set; }
}

// Data/Entities/IVersioned.cs
public interface IVersioned
{
    int Version { get; set; }
}

// Data/Entities/ITranslatedEntity.cs
public interface ITranslatedEntity<T> where T : ITranslation
{
    Guid Id { get; set; }
    IList<T> Translations { get; set; }
}

// Data/Entities/ITranslation.cs
public interface ITranslation
{
    string Name { get; set; }
    string? Description { get; set; }
    Guid LanguageId { get; set; }
}

// Data/Entities/EntityTranslation.cs
public abstract class EntityTranslation : TrackedEntity, ITenantEntity, ITranslation
{
    public string Name { get; set; } = string.Empty;
    public string? Description { get; set; }
    public Guid LanguageId { get; set; }
    public Language Language { get; set; } = null!;
    public Guid TenantId { get; set; }
}

// Correct — C# enum
public ActionStatus Status { get; set; } = ActionStatus.Open;
public EscalationSeverity Severity { get; set; } = EscalationSeverity.Medium;
public WorkflowTriggerType TriggerType { get; set; } = WorkflowTriggerType.Manual;

// Wrong — static string constants
public string Status { get; set; } = ActionStatuses.Open;  // violates ADR-0004

// Nxgn.Actions.Contracts/Actions/ActionStatus.cs
public enum ActionStatus
{
    Open = 0,
    InProgress = 1,
    UnderReview = 2,
    Closed = 3,
    Overdue = 4
}

// Nxgn.Actions.Contracts/EscalationRules/EscalationSeverity.cs
public enum EscalationSeverity
{
    Low = 0,
    Medium = 1,
    High = 2,
    Critical = 3
}

// Nxgn.Actions.Contracts/Workflows/WorkflowTriggerType.cs
public enum WorkflowTriggerType
{
    Manual = 0,
    Automatic = 1,
    Scheduled = 2
}

// Data/Entities/ActionEntity.cs
public class ActionEntity : TrackedEntity, ITenantEntity, ISoftDeletable, IVersioned
{
    public Guid TenantId { get; set; }
    public string ReferenceNumber { get; set; } = string.Empty;
    public ActionStatus Status { get; set; } = ActionStatus.Open;
    public ActionPriority Priority { get; set; } = ActionPriority.Medium;
    public DateTime? DueDate { get; set; }
    public DateTime? CompletedDate { get; set; }
    public Guid? AssignedToId { get; set; }
    public JsonDocument Metadata { get; set; } = JsonDocument.Parse("{}");

    // IVersioned
    public int Version { get; set; }

    // ISoftDeletable
    public bool IsDeleted { get; set; }
    public DateTime? DeletedDate { get; set; }
    public Guid? DeletedById { get; set; }

    // Workflow
    public Guid WorkflowDefinitionId { get; set; }
    public WorkflowDefinition WorkflowDefinition { get; set; } = null!;
    public Guid? CurrentStateId { get; set; }
    public WorkflowState? CurrentState { get; set; }

    // Navigation properties
    public ICollection<ActionEvidence> Evidence { get; set; } = [];
    public ICollection<ActionConsultation> Consultations { get; set; } = [];
    public ICollection<ActionDeadline> Deadlines { get; set; } = [];
}

// Data/Entities/WorkflowDefinition.cs
public class WorkflowDefinition : TrackedEntity, ITenantEntity, ITranslatedEntity<WorkflowDefinitionTranslation>, IVersioned
{
    public Guid TenantId { get; set; }
    public string Code { get; set; } = string.Empty;
    public bool IsActive { get; set; } = true;
    public JsonDocument Configuration { get; set; } = JsonDocument.Parse("{}");

    // IVersioned
    public int Version { get; set; }

    // ITranslatedEntity
    public IList<WorkflowDefinitionTranslation> Translations { get; set; } = [];

    // Navigation properties
    public ICollection<WorkflowState> States { get; set; } = [];
    public ICollection<ActionEntity> Actions { get; set; } = [];
}

// Data/Entities/WorkflowDefinitionTranslation.cs
public class WorkflowDefinitionTranslation : EntityTranslation
{
    public Guid WorkflowDefinitionId { get; set; }
    public WorkflowDefinition WorkflowDefinition { get; set; } = null!;
}

// Data/Entities/ActionTag.cs
public class ActionTag : Entity
{
    public Guid ActionId { get; set; }
    public Guid TagId { get; set; }

    // Navigation properties
    public ActionEntity Action { get; set; } = null!;
    public Tag Tag { get; set; } = null!;
}

// Data/Entities/Language.cs
public class Language : TrackedEntity
{
    public string Code { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public bool IsDefault { get; set; }
    public bool IsActive { get; set; } = true;
}
